import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, get, writable } from 'svelte/store';
import { createGame, createSudoku } from '../../../domain/index.js';
import { hints } from './hints';

/**
 * 创建一个全新的空数独网格。
 *
 * 网格结构为 9x9 的二维数组，空格使用 0 表示。
 * @returns {number[][]}
 */
function createEmptyGrid() {
	return Array.from({ length: 9 }, () => Array(9).fill(0))
}

/**
 * 将冲突坐标列表转换为 UI 可直接使用的 key 列表。
 *
 * key 格式为 "{col},{row}"（注意顺序为 col,row），以便与前端单元格标识保持一致。
 * @param {{ row: number, col: number }[]} conflicts - 冲突单元格坐标
 * @returns {string[]}
 */
function toConflictKeys(conflicts) {
	return conflicts.map(({ row, col }) => `${col},${row}`)
}

/**
 * 创建一个领域层的 Game 状态存储（Svelte store）。
 *
 * 该 store 负责：
 * - 维护当前题面（puzzleGrid）与玩家输入网格（userGrid）
 * - 计算冲突单元格（invalidCells）
 * - 暴露撤销/重做能力（canUndo/canRedo）
 * - 判断是否已完成（won）
 *
 * @returns {{
 *  subscribe: import('svelte/store').Writable<any>['subscribe'],
 *  generate: (difficulty: any) => void,
 *  decodeSencode: (sencode: string) => void,
 *  getSencode: () => string,
 *  getCurrentGrid: () => number[][],
 *  guess: (pos: {x:number,y:number}|null, value: number) => void,
 *  applyHint: (pos: {x:number,y:number}|null) => void,
 *  undo: () => void,
 *  redo: () => void,
 * }}
 */
function createDomainGameStore() {
	const state = writable({
		puzzleGrid: createEmptyGrid(),
		userGrid: createEmptyGrid(),
		invalidCells: [],
		canUndo: false,
		canRedo: false,
		won: false,
	})

	/** @type {ReturnType<typeof createGame> | null} */
	let game = null
	/** @type {number[][]} 当前题面（用于 sencode 编码及 UI 展示） */
	let puzzleGrid = createEmptyGrid()

	/**
	 * 将内部 game 状态发布到 Svelte store。
	 *
	 * 当 game 尚未初始化时，发布空白默认状态。
	 */
	function publish() {
		if (!game) {
			state.set({
				puzzleGrid: createEmptyGrid(),
				userGrid: createEmptyGrid(),
				invalidCells: [],
				canUndo: false,
				canRedo: false,
				won: false,
			})
			return
		}

		const sudoku = game.getSudoku()
		state.set({
			puzzleGrid: puzzleGrid.map(row => [...row]),
			userGrid: sudoku.getGrid(),
			invalidCells: toConflictKeys(sudoku.getConflicts()),
			canUndo: game.canUndo(),
			canRedo: game.canRedo(),
			won: sudoku.isSolved(),
		})
	}

	/**
	 * 使用指定题面启动一局新游戏。
	 * @param {number[][]} nextPuzzleGrid - 新题面
	 */
	function startFromGrid(nextPuzzleGrid) {
		puzzleGrid = nextPuzzleGrid.map(row => [...row])
		game = createGame({ sudoku: createSudoku(nextPuzzleGrid) })
		publish()
	}

	return {
		subscribe: state.subscribe,

		/**
		 * 生成一局新数独并开始游戏。
	 * @param {any} difficulty - 难度（由 @sudoku/sudoku 定义）
	 */
		generate(difficulty) {
			startFromGrid(generateSudoku(difficulty))
		},

		/**
		 * 从 sencode 解码并开始游戏。
	 * @param {string} sencode
	 */
		decodeSencode(sencode) {
			startFromGrid(decodeSencode(sencode))
		},

		/**
		 * 获取当前题面的 sencode 编码。
	 * @returns {string}
	 */
		getSencode() {
			return encodeSudoku(puzzleGrid)
		},

		/**
		 * 获取当前玩家网格（包含玩家输入）。
	 * @returns {number[][]}
	 */
		getCurrentGrid() {
			return get(state).userGrid
		},

		/**
		 * 玩家在指定坐标填入一个数字。
	 * @param {{x:number,y:number}|null} pos - 坐标（x=col, y=row）
	 * @param {number} value - 填入值
	 */
		guess(pos, value) {
			if (!game || pos?.x === null || pos?.y === null) {
				return
			}

			game.guess({ row: pos.y, col: pos.x, value })
			publish()
		},

		/**
		 * 对指定坐标应用提示。
	 *
	 * 会先对当前玩家网格求解，消耗一次 hint，然后把该坐标填入正确值。
	 * @param {{x:number,y:number}|null} pos
	 */
		applyHint(pos) {
			if (!game || pos?.x === null || pos?.y === null) {
				return
			}

			const solvedSudoku = solveSudoku(this.getCurrentGrid())
			hints.useHint()
			game.guess({
				row: pos.y,
				col: pos.x,
				value: solvedSudoku[pos.y][pos.x],
			})
			publish()
		},

		/**
		 * 撤销最近一次输入。
	 */
		undo() {
			if (!game) {
				return
			}

			game.undo()
			publish()
		},

		/**
		 * 重做最近一次被撤销的输入。
	 */
		redo() {
			if (!game) {
				return
			}

			game.redo()
			publish()
		},
	}
}

/**
 * 领域层 Game store 的单例。
 * @type {ReturnType<typeof createDomainGameStore>}
 */
export const domainGame = createDomainGameStore()

/**
 * 题面网格 store（仅暴露 puzzleGrid 给 UI）。
 */
export const grid = {
	/**
	 * 订阅题面网格变化。
	 * @param {(value: number[][]) => void} run
	 * @returns {import('svelte/store').Unsubscriber}
	 */
	subscribe(run) {
		return domainGame.subscribe(state => run(state.puzzleGrid))
	},

	/**
	 * 生成新题面并开始游戏。
	 * @param {any} difficulty
	 */
	generate(difficulty) {
		domainGame.generate(difficulty)
	},

	/**
	 * 从 sencode 解码题面并开始游戏。
	 * @param {string} sencode
	 */
	decodeSencode(sencode) {
		domainGame.decodeSencode(sencode)
	},

	/**
	 * 获取题面网格指定坐标的值。
	 * @param {number[][]} gridStore
	 * @param {number} x
	 * @param {number} y
	 * @returns {number}
	 */
	get(gridStore, x, y) {
		return gridStore[y][x]
	},

	/**
	 * 获取当前题面的 sencode 编码。
	 * @returns {string}
	 */
	getSencode() {
		return domainGame.getSencode()
	},
}

/**
 * 玩家输入网格 store（对外提供 set/applyHint）。
 */
export const userGrid = {
	/**
	 * 订阅玩家网格变化。
	 * @param {(value: number[][]) => void} run
	 * @returns {import('svelte/store').Unsubscriber}
	 */
	subscribe(run) {
		return domainGame.subscribe(state => run(state.userGrid))
	},

	/**
	 * 在指定坐标填入数字。
	 * @param {{x:number,y:number}|null} pos
	 * @param {number} value
	 */
	set(pos, value) {
		domainGame.guess(pos, value)
	},

	/**
	 * 对指定坐标使用提示。
	 * @param {{x:number,y:number}|null} pos
	 */
	applyHint(pos) {
		domainGame.applyHint(pos)
	},
}

/**
 * 冲突单元格 key 列表（派生 store）。
 */
export const invalidCells = derived(domainGame, $gameState => $gameState.invalidCells)

/**
 * 是否可以撤销（派生 store）。
 */
export const canUndo = derived(domainGame, $gameState => $gameState.canUndo)

/**
 * 是否可以重做（派生 store）。
 */
export const canRedo = derived(domainGame, $gameState => $gameState.canRedo)

/**
 * 游戏是否胜利（派生 store）。
 */
export const gameWonState = derived(domainGame, $gameState => $gameState.won)
